-- Migration: Add system_prompts table
-- Run on live DB: docker exec -i ainotebook-mysql mysql -uroot -painotebook_dev_password ainotebook < scripts/add_system_prompts_table.sql

CREATE TABLE IF NOT EXISTS system_prompts (
    id CHAR(36) NOT NULL,

    prompt_type ENUM('chat_panel','ai_cell') NOT NULL,
    label VARCHAR(100) NOT NULL,
    content TEXT NOT NULL,

    is_active BOOLEAN NOT NULL DEFAULT FALSE,

    created_by CHAR(36) NULL,

    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,

    PRIMARY KEY (id),
    FOREIGN KEY (created_by) REFERENCES users(id) ON DELETE SET NULL,
    INDEX idx_system_prompts_type_active (prompt_type, is_active)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

